// Pull unique title and scenes from the 'Code in JavaScript' node
const scriptData = $('Code in JavaScript').first().json;

// This logic MUST match your S3 upload naming logic exactly
const uniqueTitle = scriptData.meta.unique_title.replace(/\s+/g, '').toLowerCase();
const scenes = scriptData.scenes;

// Build the UNIQUE video URLs for the individual scenes
const videoFiles = scenes.map(scene => {
  return `http://127.0.0.1:9000/YOUR_S3_BUCKET_NAME/${uniqueTitle}_scene_${scene.id}_final.mp4`;
});

return [{
  json: {
    file_list: videoFiles
  }
}];

// Get the current item's data from the input
let item = $input.item.json;

// Check if scenes and transcript actually exist to prevent errors
if (item.scenes && item.scenes.transcript) {
    let text = item.scenes.transcript;

    // --- EMOTION & DRAMA HACKS ---

    // 1. Add dramatic "True Crime" pauses after key phrases
    text = text.replace(/(Welcome back to Deep Echoes – True Crime|get ready|get this|no seriously|here's the thing|but then)/gi, "$1...");

    // 2. Conversation "Flow": Make it sound like a real person thinking
    text = text.replace(/\bso like\b/gi, "so... like...");
    text = text.replace(/\bout of nowhere\b/gi, "...out of nowhere...");
    text = text.replace(/\band get this\b/gi, "...and... get this...");

    // --- YOUR ORIGINAL UTILITY FIXES ---

    // 3. Fix 911 (Emergency) so it's read digit-by-digit
    text = text.replace(/\b911\b/g, "nine-one-one");

    // 4. Fix AM/PM so it doesn't say the word "am" (as in "I am")
    text = text.replace(/\bam\b/gi, "A M");
    text = text.replace(/\bpm\b/gi, "P M");

    // 5. Fix Common Abbreviations
    text = text.replace(/\bSt\./g, "Street");
    text = text.replace(/\bDr\./g, "Drive");

    // 6. Fix Money (e.g., $50,000 -> 50 thousand dollars)
    text = text.replace(/\$(\d+),(\d+)/g, "$1 thousand $2 dollars");

    // Output the cleaned and "Director Approved" text
    return {
        cleaned_transcript: text
    };
} else {
    // If transcript is missing, just pass back whatever was there
    return item;
}

// 1. Get all rows and filter for only those that HAVE a Video ID
const validVideos = items
  .map(item => item.json)
  .filter(row => row['Video ID'] && row['Video ID'].toString().trim() !== '');

// 2. Safely grab the last two from the VALID list
const video1 = validVideos[validVideos.length - 1];
const video2 = validVideos[validVideos.length - 2];

// 3. Return the thumbnails only if the videos exist
return [{
  json: {
    thumb1: video1 ? `https://img.youtube.com/vi/${video1['Video ID']}/hqdefault.jpg` : '',
    thumb2: video2 ? `https://img.youtube.com/vi/${video2['Video ID']}/hqdefault.jpg` : ''
  }
}];

const title = $('Code in JavaScript').first().json.meta.unique_title.replace(/\s+/g, '').toLowerCase();
const fs = require('fs');

// We now point to the "Final Full" file (which has the scenes + music)
const content = `file 'YOUR_N8N_FILES_PATH/${title}_Final_Full.mp4'\nfile 'YOUR_N8N_FILES_PATH/outro.mp4'`;

fs.writeFileSync('YOUR_N8N_FILES_PATH/concat_list.txt', content);

return [{ json: { done: true } }];

return items.map((item) => {
  let rawText = "";

  try {
    rawText = item.json.text || item.json.response || item.json.output || "";
    if (typeof rawText !== "string") {
      rawText = JSON.stringify(rawText);
    }

    let cleanJsonString = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
    const firstChar = cleanJsonString.search(/[\{\[]/);

    if (firstChar !== -1) {
      cleanJsonString = cleanJsonString.substring(firstChar);
      let parsedData;

      try {
        parsedData = JSON.parse(cleanJsonString);
      } catch (initialError) {

        function sanitizeJson(str) {
          let result = '';
          let inString = false;
          let escaped = false;

          for (let i = 0; i < str.length; i++) {
            const char = str[i];
            if (escaped) { result += char; escaped = false; continue; }
            if (char === '\\') { result += char; escaped = true; continue; }
            if (char === '"') {
              if (!inString) {
                inString = true;
                result += char;
              } else {
                let nextNonSpace = '';
                for (let j = i + 1; j < str.length; j++) {
                  if (![' ', '\n', '\r', '\t'].includes(str[j])) {
                    nextNonSpace = str[j];
                    break;
                  }
                }
                if ([',', '}', ']', ':'].includes(nextNonSpace)) {
                  inString = false;
                  result += char;
                } else {
                  result += '\\"';
                }
              }
              continue;
            }
            result += char;
          }
          return result;
        }

        cleanJsonString = sanitizeJson(cleanJsonString);

        let openBraces = (cleanJsonString.match(/\{/g) || []).length;
        let closeBraces = (cleanJsonString.match(/\}/g) || []).length;
        let openBrackets = (cleanJsonString.match(/\[/g) || []).length;
        let closeBrackets = (cleanJsonString.match(/\]/g) || []).length;

        if (openBrackets > closeBrackets) cleanJsonString += ']'.repeat(openBrackets - closeBrackets);
        if (openBraces > closeBraces) cleanJsonString += '}'.repeat(openBraces - closeBraces);

        parsedData = JSON.parse(cleanJsonString);
      }

      if (parsedData.scenes) {
        parsedData.scenes = (Array.isArray(parsedData.scenes) ? parsedData.scenes : [parsedData.scenes]).map(scene => {
          let imgPrompt = scene.image_prompt || "";

          if (Array.isArray(scene.visuals) && scene.visuals.length > 0) {
            imgPrompt = scene.visuals[0].image_prompt || imgPrompt;
          }

          // --- NEW SANITIZATION STEP ---
          // This removes double quotes and newlines so the Animate Image node doesn't crash
          imgPrompt = imgPrompt.replace(/"/g, "'").replace(/\n/g, " ");
          let safeTranscript = (scene.transcript || "").replace(/"/g, "'").replace(/\n/g, " ");

          return {
            ...scene,
            image_prompt: imgPrompt,
            transcript: safeTranscript
          };
        });
      }

      return { json: parsedData };

    } else {
      return { json: { error: "no json found", raw: rawText } };
    }

  } catch (error) {
    return {
      json: {
        error: "parsing failed",
        details: error.message,
        suggestion: "AI response was truncated or heavily malformed.",
        raw: rawText
      }
    };
  }
});

